<div class="wrap ccf-admin-wrap"><h1>Revisión de movimientos</h1>
<table class="widefat striped"><thead><tr><th>ID</th><th>Fecha</th><th>Descripción</th><th>Categoría</th><th>Adjuntos</th><th>Acción rápida</th></tr></thead><tbody><?php foreach ( $queue as $item ) : ?><tr><td><?php echo esc_html( $item['id'] ); ?></td><td><?php echo esc_html( $item['transaction_date'] ); ?></td><td><?php echo esc_html( $item['description'] ); ?></td><td><?php echo esc_html( $item['category_id'] ?: 'Sin categoría' ); ?></td><td><?php echo esc_html( $item['attachment_count'] ); ?></td><td><form method="post"><?php wp_nonce_field( 'ccf_mark_review_action' ); ?><input type="hidden" name="transaction_id" value="<?php echo esc_attr( $item['id'] ); ?>"><label><input type="checkbox" name="reviewed" value="1">Revisado</label><label><input type="checkbox" name="flagged" value="1">Pendiente</label><button class="button" name="ccf_mark_review" value="1">Guardar</button></form></td></tr><?php endforeach; ?></tbody></table></div>
